import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

/**
 * Annotation page supporting:
 *   - BBox & Polygon
 *   - Esc to cancel in-progress annotation
 *   - Next/Prev image via Arrow keys
 *   - Exports: COCO, YOLO, Pascal
 *   - Fill shapes with label color
 *   - Undo/Redo (Ctrl+Z / Ctrl+Y)
 */
export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses, files } = folderInfo;

  // Instead of "const [annotations, setAnnotations] = useState({})"
  // we add "history" & "historyIndex" for undo/redo:
  const [annotations, setAnnotations] = useState({});
  const [history, setHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Currently displayed image index
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tools
  const [selectedTool, setSelectedTool] = useState('move'); // 'move', 'bbox', 'polygon'
  const [selectedLabelClass, setSelectedLabelClass] = useState(labelClasses[0]?.name || '');
  const [scale, setScale] = useState(1.0);

  // Get current image's shapes
  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  // --------------------------------------
  // Helper to update "annotations" with Undo/Redo support
  // --------------------------------------
  function updateAnnotations(newAnnotations) {
    // 1) If we've undone some steps, slice off "future" states
    setHistory(prev => {
      const truncated = prev.slice(0, historyIndex + 1);
      // 2) Add a deep clone of the new state
      const clone = JSON.parse(JSON.stringify(newAnnotations));
      return [...truncated, clone];
    });
    // 3) Point historyIndex to the end
    setHistoryIndex(i => i + 1);
    // 4) Set the actual annotations state
    setAnnotations(newAnnotations);
  }

  // This gets used whenever shapes for the current image change
  const handleAnnotationsChange = (newShapes) => {
    // Insert or replace the shapes for the currentFileUrl
    const updated = { ...annotations, [currentFileUrl]: newShapes };
    // Then store it via updateAnnotations
    updateAnnotations(updated);
  };

  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // Next/Prev image
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex(i => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex(i => i + 1);
  };

  // Zoom
  const handleZoomIn = () => setScale(s => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale(s => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // Save => POST to server
  const handleSave = async () => {
    const bodyData = { folderId, taskName, labelClasses, annotations };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData)
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  // --------------------------
  // Undo / Redo
  // --------------------------
  function handleUndo() {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setAnnotations(history[newIndex]);
    }
  }

  function handleRedo() {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setAnnotations(history[newIndex]);
    }
  }

  // Keyboard Shortcuts
  React.useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;

      // Tools
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 's' || key === 'S') {
        e.preventDefault();
        handleSave();
      } else if (key === 'Escape') {
        // Cancel in-progress shape
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      } else if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }

      // Undo/Redo: (Check for Ctrl or Cmd)
      if ((e.ctrlKey || e.metaKey) && key.toLowerCase() === 'z') {
        e.preventDefault();
        handleUndo();
      } else if ((e.ctrlKey || e.metaKey) && key.toLowerCase() === 'y') {
        e.preventDefault();
        handleRedo();
      }
    };

    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [handleSave, historyIndex, history, currentShapes]);

  // Export modal
  const [exportOpen, setExportOpen] = useState(false);
  const openExport = () => setExportOpen(true);
  const closeExport = () => setExportOpen(false);

  const exportAnnotations = (format) => {
    if (format === 'coco') downloadCOCO();
    else if (format === 'yolo') downloadYOLO();
    else if (format === 'pascal') downloadPascal();
    closeExport();
  };

  // Some format helpers
  function getBBoxFromPoints(points) {
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    points.forEach(pt => {
      if (pt.x < minX) minX = pt.x;
      if (pt.y < minY) minY = pt.y;
      if (pt.x > maxX) maxX = pt.x;
      if (pt.y > maxY) maxY = pt.y;
    });
    return [minX, minY, maxX - minX, maxY - minY];
  }
  function downloadFile(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  // COCO
  function downloadCOCO() {
    let images = [];
    let annotationsList = [];
    let annId = 1, imgId = 1;

    for (const [imageUrl, shapes] of Object.entries(annotations)) {
      const fileObj = files.find(f => f.url === imageUrl);
      const imageName = fileObj?.originalname || 'unknown.jpg';
      images.push({ id: imgId, file_name: imageName, width: 0, height: 0 });

      shapes.forEach(shape => {
        const catIndex = labelClasses.findIndex(l => l.name === shape.label);
        const categoryId = catIndex >= 0 ? catIndex + 1 : 1;
        if (shape.type === 'bbox') {
          annotationsList.push({
            id: annId++, image_id: imgId, category_id: categoryId,
            bbox: [shape.x, shape.y, shape.width, shape.height],
            segmentation: [],
            area: Math.abs(shape.width * shape.height),
            iscrowd: 0
          });
        } else {
          // polygon
          const polygonPts = shape.points.flatMap(pt => [pt.x, pt.y]);
          annotationsList.push({
            id: annId++, image_id: imgId, category_id: categoryId,
            segmentation: [polygonPts],
            bbox: getBBoxFromPoints(shape.points),
            area: 0,
            iscrowd: 0
          });
        }
      });
      imgId++;
    }

    const categories = labelClasses.map((lc, i) => ({
      id: i + 1, name: lc.name, supercategory: 'none'
    }));
    const coco = { images, annotations: annotationsList, categories };

    const blob = new Blob([JSON.stringify(coco, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    downloadFile(url, 'coco_annotations.json');
  }

  // YOLO
  function downloadYOLO() {
    let lines = [];
    for (const [imageUrl, shapes] of Object.entries(annotations)) {
      const fileObj = files.find(f => f.url === imageUrl);
      const imageName = fileObj?.originalname || 'unknown.jpg';
      lines.push(`# YOLO for ${imageName}`);
      shapes.forEach(shape => {
        const catIndex = labelClasses.findIndex(l => l.name === shape.label);
        let classId = catIndex >= 0 ? catIndex : 0;
        let bx = 0, by = 0, bw = 0, bh = 0;
        if (shape.type === 'bbox') {
          bx = shape.x + shape.width / 2;
          by = shape.y + shape.height / 2;
          bw = shape.width;
          bh = shape.height;
        } else {
          // polygon => bounding box
          const [x, y, w, h] = getBBoxFromPoints(shape.points);
          bx = x + w / 2; by = y + h / 2;
          bw = w; bh = h;
        }
        lines.push(`${classId} ${bx.toFixed(2)} ${by.toFixed(2)} ${bw.toFixed(2)} ${bh.toFixed(2)}`);
      });
      lines.push('');
    }
    const blob = new Blob([lines.join('\n')], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    downloadFile(url, 'yolo_annotations.txt');
  }

  // Pascal VOC (all in one XML for simplicity)
  function downloadPascal() {
    let output = [];
    output.push(`<pascal_voc_annotations>`);

    for (const [imageUrl, shapes] of Object.entries(annotations)) {
      const fileObj = files.find(f => f.url === imageUrl);
      const imageName = fileObj?.originalname || 'unknown.jpg';
      output.push(`  <image file="${imageName}">`);

      shapes.forEach(shape => {
        const label = shape.label || 'unknown';
        if (shape.type === 'bbox') {
          const xmin = shape.x, ymin = shape.y;
          const xmax = shape.x + shape.width, ymax = shape.y + shape.height;
          output.push(`    <object>`);
          output.push(`      <name>${label}</name>`);
          output.push(`      <bndbox><xmin>${xmin}</xmin><ymin>${ymin}</ymin><xmax>${xmax}</xmax><ymax>${ymax}</ymax></bndbox>`);
          output.push(`    </object>`);
        } else {
          // polygon => bounding box
          const [x, y, w, h] = getBBoxFromPoints(shape.points);
          const xmin = x, ymin = y;
          const xmax = x + w, ymax = y + h;
          output.push(`    <object>`);
          output.push(`      <name>${label}</name>`);
          output.push(`      <bndbox><xmin>${xmin}</xmin><ymin>${ymin}</ymin><xmax>${xmax}</xmax><ymax>${ymax}</ymax></bndbox>`);
          output.push(`    </object>`);
        }
      });

      output.push(`  </image>`);
    }

    output.push(`</pascal_voc_annotations>`);
    const xmlStr = output.join('\n');
    const blob = new Blob([xmlStr], { type: 'application/xml' });
    const url = URL.createObjectURL(blob);
    downloadFile(url, 'pascal_annotations.xml');
  }

  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={openExport}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div className="annotate-main">
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            Polygon (P)
          </label>

          <h3 style={{ marginTop: 16 }}>Active Label</h3>
          <select
            value={selectedLabelClass}
            onChange={(e) => setSelectedLabelClass(e.target.value)}
          >
            {labelClasses.map((lc, i) => (
              <option key={i} value={lc.name}>{lc.name}</option>
            ))}
          </select>

          <div className="note-area">
            <p><strong>Shortcuts:</strong></p>
            <ul>
              <li>M/B/P => Tools</li>
              <li>S => Save</li>
              <li>Esc => Cancel in-progress</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
            </ul>
          </div>
        </div>

        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                labelClasses.find(l => l.name === selectedLabelClass)?.color || '#ff0000'
              }
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>No images found</div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={labelClasses}
        />
      </div>

      {exportOpen && (
        <div className="export-modal-backdrop">
          <div className="export-modal">
            <h2>Export Annotations</h2>
            <p>Select format:</p>
            <div className="export-buttons">
              <button onClick={() => exportAnnotations('coco')}>COCO</button>
              <button onClick={() => exportAnnotations('yolo')}>YOLO</button>
              <button onClick={() => exportAnnotations('pascal')}>Pascal VOC</button>
            </div>
            <button className="close-btn" onClick={closeExport}>Close</button>
          </div>
        </div>
      )}
    </div>
  );
}
